import{j as e}from"./vendor-Dh_dlHsl.js";import{C as t,A as a,N as s,E as i,W as o,P as n}from"./subject-01-thinking-in-agents-BIrOrpH9.js";const T={id:"trust-and-safety",title:"Trust and Safety",description:"The guardrails that make autonomous agents safe — permission models, blast radius, and designing for safety.",icon:"🛡️",colorHex:"#dc2626",difficulty:"beginner",estimatedHours:8,prerequisites:["thinking-in-agents"],chapters:[{id:"c1-safety-problem",title:"The Safety Problem",description:"Why autonomous systems need boundaries and how to think about risk.",difficulty:"beginner",estimatedMinutes:80,sections:[{id:"s1-why-boundaries",title:"Why Autonomous Systems Need Boundaries",description:"The fundamental tension between autonomy and safety.",difficulty:"beginner",readingMinutes:10},{id:"s2-blast-radius",title:"Blast Radius",description:"Understanding the consequences of agent mistakes — from harmless to catastrophic.",difficulty:"beginner",readingMinutes:12},{id:"s3-reversible-irreversible",title:"Reversible vs Irreversible Actions",description:"A critical distinction that shapes how much freedom agents should have.",difficulty:"beginner",readingMinutes:10},{id:"s4-cost-asking-vs-acting",title:"The Cost of Asking vs Acting Wrong",description:"Why pausing to confirm is almost always cheaper than recovering from a mistake.",difficulty:"beginner",readingMinutes:10}]},{id:"c2-permission-models",title:"Permission Models",description:"Different approaches to controlling what agents can and cannot do.",difficulty:"intermediate",estimatedMinutes:100,sections:[{id:"s1-ask-every-time",title:"Ask Every Time",description:"Maximum safety, minimum autonomy — the default safe mode.",difficulty:"beginner",readingMinutes:10},{id:"s2-plan-then-execute",title:"Plan-Then-Execute",description:"Approve a batch of actions, then let the agent run them all.",difficulty:"intermediate",readingMinutes:10},{id:"s3-rule-based",title:"Rule-Based Auto-Approval",description:"Pattern matching for trust — wildcards and allow-lists.",difficulty:"intermediate",readingMinutes:12},{id:"s4-classifier-based",title:"Classifier-Based Approval",description:"Letting machines judge risk — automated permission decisions.",difficulty:"advanced",readingMinutes:10},{id:"s5-full-trust",title:"Full Trust",description:"When guardrails come down — understanding the risks and valid use cases.",difficulty:"intermediate",readingMinutes:10}]},{id:"c3-designing-safety",title:"Designing for Safety",description:"Practical patterns for building agents that are safe by default.",difficulty:"intermediate",estimatedMinutes:100,sections:[{id:"s1-least-privilege",title:"Least Privilege",description:"Give agents only what they need — no more, no less.",difficulty:"intermediate",readingMinutes:10},{id:"s2-fail-closed",title:"Fail-Closed",description:"When in doubt, ask — the principle of defaulting to safety.",difficulty:"intermediate",readingMinutes:10},{id:"s3-human-in-loop",title:"Human-in-the-Loop",description:"Strategic checkpoints for risky actions — when to pause and ask.",difficulty:"intermediate",readingMinutes:12},{id:"s4-sandboxing",title:"Sandboxing",description:"Containing agent actions within safe boundaries — isolation strategies.",difficulty:"intermediate",readingMinutes:10},{id:"s5-secrets-sensitive",title:"Secrets and Sensitive Data",description:"What agents must never touch — credentials, keys, and private information.",difficulty:"intermediate",readingMinutes:10}]}]};function r(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Why Agents Need Boundaries"}),e.jsx("p",{children:"Agents are powerful precisely because they can act autonomously — reading files, calling APIs, sending messages, and making decisions without constant supervision. That same autonomy is what makes unconstrained agents dangerous. Without deliberate boundaries, an agent that misunderstands a goal can pursue it relentlessly in ways its designers never intended."}),e.jsx(t,{title:"The Autonomy–Safety Tension",number:"Concept 3.1",children:"Every increase in an agent's autonomy is also an increase in the potential magnitude of its mistakes. Boundaries are the mechanism by which we let agents be useful without letting them be catastrophic. They are not restrictions on capability — they are the conditions under which capability can be safely deployed."}),e.jsx("p",{children:"Human organizations solve this with roles, authorizations, and approval chains. A junior employee has access only to the systems they need for their job. A purchase above a certain value requires a manager's sign-off. These constraints exist not because the employee is untrustworthy, but because errors are inevitable and the cost of a mistake should be bounded."}),e.jsx(a,{title:"Power Tools and Guards",children:"A circular saw with no blade guard can cut anything — including the operator's hand. The guard does not make the saw less powerful; it makes its power safe to use in proximity to humans. Agent safety boundaries work the same way. They are engineering choices about where the sharp edges are allowed to reach."}),e.jsx(s,{title:"Boundaries are not just for bad actors",type:"info",children:"Most boundary violations by AI agents are not caused by adversarial inputs or malicious intent. They stem from ambiguous instructions, unexpected environments, or subtle misunderstandings of what the user actually wanted. Boundaries protect against honest mistakes as much as against attacks."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"wb-1",difficulty:"beginner",question:'An agent is asked to "clean up old files." Without boundaries, what are two different ways this instruction could be interpreted that lead to very different outcomes?',hint:'Consider what "old" means and what "clean up" might mean in different contexts.',solution:'The agent might archive files older than 30 days (safe) or permanently delete any file not modified in the last week (destructive). Both satisfy the literal instruction. Boundaries — like "only move, never delete" or "ask before acting on files newer than 90 days" — constrain the interpretation space.'},{id:"wb-2",difficulty:"intermediate",question:"Why is an agent that can only read data still a potential safety concern, even though it cannot modify anything?",hint:"Think about what reading data at scale could enable.",solution:"A read-only agent can still exfiltrate sensitive information, expose private data to unauthorized parties, or exhaust rate limits and quotas. Data confidentiality is a distinct concern from data integrity, and boundaries must address both."},{id:"wb-3",difficulty:"intermediate",question:"Describe the difference between a boundary that prevents an action and a boundary that requires approval before an action. When would you prefer each?",hint:"Think about the trade-off between safety and usefulness.",solution:"A hard boundary blocks an action entirely — useful when no circumstance justifies the action. An approval boundary pauses and asks a human — useful when the action is sometimes appropriate but high-stakes. Hard boundaries maximize safety; approval boundaries preserve flexibility while maintaining oversight."}]})]})}const j=Object.freeze(Object.defineProperty({__proto__:null,default:r},Symbol.toStringTag,{value:"Module"}));function l(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Blast Radius"}),e.jsx("p",{children:"When an agent makes a mistake, the question is not just whether it made one — it's how much damage that mistake can cause before it is caught and corrected. This potential damage is called the blast radius: the maximum harm reachable from a single point of failure."}),e.jsx(t,{title:"Blast Radius",number:"Concept 3.2",children:"The blast radius of an agent action is the maximum negative impact that can result if that action goes wrong. It is determined by the scope of access, the reversibility of the action, and the speed at which errors propagate before they are noticed. Good safety design minimizes blast radius before any mistake happens."}),e.jsxs("p",{children:["Blast radius has two independent dimensions. The first is ",e.jsx("strong",{children:"breadth"}),": how many things can be affected? An agent with access to one database table has a narrower breadth than one with access to an entire production cluster. The second is"," ",e.jsx("strong",{children:"depth"}),": how severely can each thing be affected? Appending a log entry is shallow; dropping a table is deep."]}),e.jsx(a,{title:"Controlled Burns",children:"Forest firefighters deliberately set small, controlled fires to consume undergrowth that would otherwise fuel catastrophic wildfires. The controlled burn has a defined blast radius — it cannot spread beyond the firebreak. Agent permissions work the same way: define the firebreak before the burn starts, not after smoke appears."}),e.jsx(o,{title:"Speed amplifies blast radius",children:"An agent that acts slowly gives humans time to notice and intervene. An agent that executes thousands of operations per second can destroy a year of data in the time it takes someone to read a Slack notification. Rate limiting and operation counts are blast radius controls, not just performance considerations."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"br-1",difficulty:"beginner",question:"Rank these three agent actions by blast radius, from smallest to largest, and explain your reasoning: (a) append a line to a log file, (b) send a bulk email to all customers, (c) read a public webpage.",hint:"Consider reversibility and how many people or systems are affected.",solution:"(c) read a webpage — no side effects at all. (a) append to log — minimal, local, easily corrected. (b) bulk email — high blast radius: emails cannot be unsent, many people affected, reputational damage is real and lasting."},{id:"br-2",difficulty:"intermediate",question:"An agent has permission to modify any record in a customer database. Suggest two architectural changes that would reduce its blast radius without removing its ability to do its job.",hint:"Think about scope restriction and rollback capabilities.",solution:"First, scope access to only the tables the agent actually needs (least-privilege). Second, require writes to go through a staging or soft-delete mechanism so all changes are reversible for a defined window before permanent commit."},{id:"br-3",difficulty:"advanced",question:"Why might an agent with read-only access to a messaging platform have a larger blast radius than an agent with write access to a small internal database? What does this reveal about how blast radius should be measured?",hint:"Consider what the read-only agent could do with what it reads.",solution:"If the messaging platform contains sensitive conversations, PII, or credentials, a read-only agent could exfiltrate high-value data — a large privacy blast radius. Blast radius must be measured across multiple dimensions: data sensitivity, number of affected parties, and downstream misuse potential — not just write permissions."}]})]})}const A=Object.freeze(Object.defineProperty({__proto__:null,default:l},Symbol.toStringTag,{value:"Module"}));function c(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Reversible vs. Irreversible Actions"}),e.jsx("p",{children:"Not all agent actions are equally consequential. One of the most important distinctions in agent safety is between reversible and irreversible actions. Reversible actions can be undone; irreversible ones cannot. This single property shapes how much caution an agent should apply before executing any given step."}),e.jsx(t,{title:"Reversibility Spectrum",number:"Concept 3.3",children:"Actions fall on a spectrum from fully reversible to fully irreversible. Moving a file to a trash folder is nearly reversible. Sending an email is not reversible but is limited in scope. Deleting a database without backup is irreversible at scale. Agents should treat position on this spectrum as a primary input to the decision of whether to act autonomously or seek confirmation."}),e.jsx("p",{children:"Reversibility is not a binary property — it is a function of time, cost, and completeness. A deleted file is reversible if a backup exists and is recent. The same deletion becomes irreversible if the backup is six months old and the file was created yesterday. Designing agents well means building the infrastructure for reversibility: snapshots, audit logs, soft deletes, and rollback windows."}),e.jsx(a,{title:"Git Commits vs. Published Posts",children:"Committing code to a local repository is reversible — you can amend, reset, or revert freely. Pushing to a public repository increases the cost of reversal. Publishing and announcing a release makes reversal even harder due to downstream dependencies. The action looks similar at each stage but the reversibility decreases dramatically. Agent actions have the same layered structure."}),e.jsx(n,{title:"Prefer Reversible Paths",number:"Principle 3.1",children:"When an agent faces a choice between two approaches that both achieve the goal, prefer the more reversible one. Reversibility is not a constraint to work around — it is a design criterion to optimize for. This is especially important in agentic pipelines where errors compound across many steps before anyone notices."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"ri-1",difficulty:"beginner",question:"For each action, classify it as reversible, partially reversible, or irreversible, and briefly explain: (a) renaming a file, (b) posting a public tweet, (c) charging a customer's credit card.",hint:"Think about technical reversibility and practical reversibility separately.",solution:"(a) Reversible — rename back or restore from backup. (b) Partially reversible — can delete but retweets/screenshots persist. (c) Partially reversible — can issue refund but transaction record remains and customer experience is already affected."},{id:"ri-2",difficulty:"intermediate",question:"An agent is about to permanently delete 500 archived records to free up storage. Describe two system-level mechanisms that could make this action more reversible without changing the agent's logic.",hint:"Think about what happens at the storage layer before and after deletion.",solution:"First, implement a soft-delete pattern: mark records as deleted and move them to an archive table with a retention window before physical removal. Second, take an automated snapshot of the affected records to cold storage before executing the deletion, creating a point-in-time recovery option."},{id:"ri-3",difficulty:"advanced",question:"Why does the reversibility of an action often decrease as a pipeline grows longer, even if each individual step remains reversible in isolation?",hint:"Think about downstream dependencies and compounding state changes.",solution:"Each step may trigger downstream actions in other systems — notifications sent, caches invalidated, third-party APIs called, or other agents triggered. Reversing step 3 may technically be possible, but steps 4–8 that ran because of step 3 may have already produced irreversible effects. Reversibility of a pipeline must be evaluated holistically, not step-by-step."}]})]})}const q=Object.freeze(Object.defineProperty({__proto__:null,default:c},Symbol.toStringTag,{value:"Module"}));function d(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"The Cost of Asking vs. The Cost of Acting"}),e.jsx("p",{children:"Every agent decision involves an implicit trade-off: ask a human for clarification or proceed autonomously. Both choices have costs. Asking interrupts the human, slows the workflow, and — if done too often — trains users to ignore confirmations. Acting without asking risks taking the wrong action, possibly an irreversible one. Neither extreme is correct."}),e.jsx(t,{title:"The Ask–Act Trade-off",number:"Concept 3.4",children:"The decision to ask versus act should be calibrated against two costs: the cost of an unnecessary interruption (friction, user fatigue, broken focus) and the cost of an unchecked wrong action (damage, reversal effort, trust erosion). High-stakes irreversible actions warrant asking even at high friction cost. Routine reversible tasks warrant autonomous action even with some uncertainty."}),e.jsx("p",{children:'The cost of asking is not zero. Users who are interrupted too frequently begin approving confirmations reflexively — the same phenomenon as "alert fatigue" in security systems. An agent that asks for confirmation on every small step creates a false sense of oversight while actually reducing it, because humans stop reading what they are approving.'}),e.jsx(s,{title:"Automation bias",type:"warning",children:"Research consistently shows that humans in supervisory roles over automated systems tend to over-trust automation over time. This means confirmation dialogs lose effectiveness the more routine they become. Reserve human checkpoints for genuinely high-stakes decisions, so they receive the attention they deserve."}),e.jsx(n,{title:"Match Friction to Stakes",number:"Principle 3.2",children:'Design agent checkpoints proportional to the stakes of the action. Routine, reversible, low-blast-radius operations should run without interruption. Novel, irreversible, or high-blast-radius operations should pause and surface a clear, specific question — not a generic "are you sure?" that triggers reflexive approval.'}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"ca-1",difficulty:"beginner",question:'An agent that helps with email drafts asks "Should I send this?" before every single email, including routine internal meeting confirmations. What is the likely long-term behavioral effect on users, and why is this a safety problem?',hint:"Think about what happens to human attention when prompts become routine.",solution:'Users will begin clicking "yes" without reading, because the prompt has become noise. This creates automation bias — users appear to be in the loop but are not providing real oversight. High-stakes emails may be sent without genuine review because the confirmation habit has been dulled by low-stakes repetition.'},{id:"ca-2",difficulty:"intermediate",question:"Design a simple decision rule an agent could use to determine whether to ask before acting. What two factors should always be in that rule, and what is one factor that should be context-dependent?",hint:"Revisit the blast radius and reversibility concepts from earlier sections.",solution:"Always include: (1) reversibility — if the action cannot be undone, ask; (2) blast radius — if many systems or people are affected, ask. Context-dependent: novelty — if this is the first time the agent has performed this class of action in this environment, more caution is warranted even for lower-stakes operations."},{id:"ca-3",difficulty:"advanced",question:"A team argues that their agent should ask for permission before every action to maximize safety. Construct the strongest counter-argument against this position.",hint:'Consider what "safety" really means at the system level, not just the action level.',solution:"Maximizing confirmations does not maximize safety — it creates alert fatigue, erodes the quality of human oversight, and incentivizes users to bypass the agent entirely or use less safe alternatives. True safety requires proportionate oversight: reserve human attention for the decisions where it genuinely matters, so that attention is available and meaningful when it is needed most."}]})]})}const P=Object.freeze(Object.defineProperty({__proto__:null,default:d},Symbol.toStringTag,{value:"Module"}));function h(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Ask Every Time"}),e.jsx("p",{children:"The simplest permission model is also the most conservative: before taking any action, the agent asks a human for explicit approval. No action proceeds without a fresh authorization. This model trades autonomy entirely for transparency — the human is always in the loop, and the agent's footprint is limited to what was directly sanctioned."}),e.jsx(t,{title:"Ask-Every-Time Permission Model",number:"Concept 3.5",children:"In the ask-every-time model, the agent proposes each action individually and waits for human confirmation before executing. Approval is not remembered or generalized — each new action requires a new approval, even if an identical action was approved moments before. This maximizes human control at the cost of speed and convenience."}),e.jsx(a,{title:"The Notary Model",children:`Some legal documents require notarization — a witness who verifies identity and intent for each signature, every time, regardless of how many documents you've signed before. The notary does not say "I remember you from last week, go ahead." Every transaction is independently verified. Ask-every-time agents operate on the same principle.`}),e.jsx("p",{children:"This model is appropriate when the cost of a wrong action is extremely high, when the agent is operating in a new or unfamiliar environment, or when the actions being taken are genuinely novel each time. It is poorly suited to high-frequency, repetitive tasks where the confirmation process would overwhelm the human operator."}),e.jsx(s,{title:"When to use ask-every-time",type:"info",children:"Ask-every-time is a good starting point when deploying a new agent into production for the first time. It lets operators build confidence in the agent's behavior before relaxing the permission model. Think of it as the highest rung on a trust ladder — you start there and descend as trust is established."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"aet-1",difficulty:"beginner",question:"Name two categories of agent tasks where an ask-every-time model is appropriate, and two categories where it is not. Explain your reasoning briefly.",hint:"Think about frequency, stakes, and novelty of each task type.",solution:"Appropriate: (1) One-off destructive operations like bulk deletion or production deployments — high stakes, low frequency. (2) Actions that touch external parties like sending communications — consequences outside system. Not appropriate: (1) Routine data reads needed hundreds of times per hour. (2) Internal, reversible computations that can be rolled back trivially."},{id:"aet-2",difficulty:"intermediate",question:"An agent using the ask-every-time model is helping process 200 customer support tickets. It asks for approval before labeling each ticket. Describe the likely outcome, and suggest a modification that preserves safety while being more practical.",hint:"Think about what happens to the human's attention across 200 approvals.",solution:"The operator will experience severe alert fatigue and begin rubber-stamping approvals after the first few dozen. Safety is illusory. Modification: switch to a plan-then-execute model where the agent presents its labeling plan for all 200 tickets at once for review, then executes after a single approval of the plan — maintaining oversight without 200 interruptions."},{id:"aet-3",difficulty:"intermediate",question:"What is the hidden cost of ask-every-time that is easy to miss when designing a system, but becomes apparent when operating it?",hint:"Think about what this model requires from the human side of the system.",solution:"Ask-every-time requires a continuously available human with sufficient context to make informed decisions. In practice, humans go to meetings, sleep, and get distracted. The agent either blocks indefinitely waiting for approval (reducing throughput to zero) or the organization creates workarounds like auto-approvers that defeat the model's safety intent entirely."}]})]})}const I=Object.freeze(Object.defineProperty({__proto__:null,default:h},Symbol.toStringTag,{value:"Module"}));function u(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Plan-Then-Execute"}),e.jsx("p",{children:"The plan-then-execute model separates the work of deciding what to do from the work of doing it. The agent first generates a complete plan — a sequence of proposed actions — and presents it to a human for review. Only after the plan is approved does the agent begin execution. This concentrates human oversight into a single checkpoint rather than scattering it across every individual action."}),e.jsx(t,{title:"Plan-Then-Execute Permission Model",number:"Concept 3.6",children:"In the plan-then-execute model, the agent reasons through a task and produces an explicit action plan before taking any real-world steps. A human reviews the full plan, can modify or reject it, and then approves it as a whole. Execution follows the approved plan autonomously. The key insight is that oversight happens at the planning phase, where course correction is cheapest."}),e.jsx(a,{title:"The Surgical Checklist",children:"Before a complex surgery, the surgical team reviews the procedure plan together: what will be done, in what order, with what instruments, and what the abort conditions are. Everyone agrees before the first incision. The surgery then proceeds without a committee vote for every cut. The planning session is the safety gate, not the execution."}),e.jsx("p",{children:"Plan-then-execute is well suited to tasks that are too long for step-by-step approval but too consequential for fully autonomous execution. It works best when the action space is predictable enough that a complete plan can be specified in advance. It breaks down when the agent must react to information it discovers mid-execution, because the plan may become invalid as conditions change."}),e.jsx(n,{title:"Make Plans Inspectable",number:"Principle 3.3",children:`A plan is only useful as a safety mechanism if humans can actually understand it. Plans should be expressed in human-readable terms that describe intent, not just low-level operations. "Delete all rows where status is 'archived' and created_at is before 2023" is inspectable. A list of opaque database transaction IDs is not.`}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"pte-1",difficulty:"beginner",question:"What is the main advantage of plan-then-execute over ask-every-time, and what is the main risk introduced by concentrating approval into a single checkpoint?",hint:"Think about the human's cognitive load and what they can realistically evaluate in one review.",solution:"Advantage: dramatically reduces interruptions — one review for a 50-step plan instead of 50 reviews. Main risk: the human may not carefully evaluate all 50 steps. Reviewers tend to skim long plans and miss subtle issues in the middle. The plan must be structured to make anomalies easy to spot."},{id:"pte-2",difficulty:"intermediate",question:"An agent is executing an approved 20-step plan and at step 12 discovers that the data it is working with is structured differently than expected. Should the agent continue, stop and re-plan, or improvise? Defend your answer.",hint:"Consider what the original approval was actually authorizing.",solution:"The agent should stop and re-plan. The human's approval was for the specific plan as written, based on assumptions about the environment. If those assumptions no longer hold, continuing constitutes acting outside the scope of what was approved. The agent should surface the new information, propose a revised plan, and seek fresh approval."},{id:"pte-3",difficulty:"advanced",question:"Design a plan format that would make it easy for a non-technical reviewer to catch a dangerous step hidden among many routine steps. What elements would you include?",hint:"Think about how humans scan documents for risk.",solution:'Include: (1) A risk summary at the top listing any irreversible or high-blast-radius steps. (2) Color or symbol coding for each step by reversibility. (3) Plain-language descriptions of what each step does and why. (4) Explicit "point of no return" markers where rollback becomes impossible. (5) A diff view if the plan modifies existing data, showing before and after.'}]})]})}const C=Object.freeze(Object.defineProperty({__proto__:null,default:u},Symbol.toStringTag,{value:"Module"}));function m(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Rule-Based Permissions"}),e.jsx("p",{children:"Rule-based permission models pre-specify exactly what an agent is and is not allowed to do, in the form of explicit conditions. When an agent contemplates an action, it checks the rules: if the action matches an allowed pattern, it proceeds autonomously; if it matches a denied pattern, it stops. No human needs to be consulted for any action that falls within the pre-defined rules."}),e.jsx(t,{title:"Rule-Based Permission Model",number:"Concept 3.7",children:'A rule-based permission model encodes authorization decisions as explicit, evaluatable conditions defined before the agent runs. Rules may allow actions ("the agent may read any file in /reports"), deny them ("the agent may never modify files in /production"), or escalate them ("any deletion requires confirmation"). The model is deterministic: given the same action and the same rule set, the outcome is always the same.'}),e.jsx("p",{children:"The strength of rule-based models is predictability and auditability. The rules can be reviewed by security teams, version-controlled, and tested. There is no ambiguity about whether a specific action is permitted — the rules either cover it or they do not. This makes rule-based permissions the most common choice for regulated industries and security-sensitive deployments."}),e.jsx(s,{title:"Rule coverage gaps",type:"warning",children:"Rules only govern actions they explicitly address. When an agent encounters a situation not covered by any rule, the system must decide: fail closed (deny by default) or fail open (allow by default). For safety-critical systems, always fail closed — uncovered actions are denied until a rule explicitly permits them."}),e.jsx(o,{title:"Rules can be gamed",children:"Rule-based models are vulnerable to exact-match bypasses. An agent that technically complies with every rule while violating the intent behind them is a real risk. Rules should be written to capture intent, not just syntax. Supplement rule checks with periodic audits of what the agent actually does versus what designers intended."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"rb-1",difficulty:"beginner",question:"Write three rules (in plain English) for a customer support agent that handles refund requests. Include at least one allow rule, one deny rule, and one escalation rule.",hint:"Think about the range of things a support agent might want to do.",solution:`Allow: "Process refunds up to $50 without manager approval." Deny: "Never access a customer's payment card details directly." Escalate: "Any refund request over $200 must be routed to a human agent for review before processing."`},{id:"rb-2",difficulty:"intermediate",question:'A rule says "the agent may send emails only to addresses in the approved contacts list." An attacker tricks the agent into adding a malicious address to the contacts list first, then sending an email to it. What class of vulnerability is this, and how would you mitigate it?',hint:"The attack involves two steps — think about what the first step exploits.",solution:"This is a privilege escalation via rule precondition manipulation. The rule's allow condition (membership in the contacts list) is only as safe as the mechanism that manages the list. Mitigation: treat the contacts list itself as a sensitive resource with its own permission rules — require human approval to add new addresses, and audit additions separately from email sends."},{id:"rb-3",difficulty:"advanced",question:"Compare rule-based and ask-every-time models on three dimensions: scalability, predictability, and resilience to novel situations. Which model performs better on each dimension, and why?",hint:"Think about what happens to each model as task volume increases and as situations become more unusual.",solution:"Scalability: Rule-based wins — rules execute without human involvement, scaling to any volume. Ask-every-time bottlenecks at human availability. Predictability: Rule-based wins — the same action always produces the same decision. Ask-every-time varies with human judgment and attention. Novel situations: Ask-every-time wins — a human can reason about an unprecedented scenario. Rules either block it (fail closed) or allow it incorrectly (gap in coverage), with no intelligent handling of novelty."}]})]})}const S=Object.freeze(Object.defineProperty({__proto__:null,default:m},Symbol.toStringTag,{value:"Module"}));function p(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Classifier-Based Permissions"}),e.jsx("p",{children:"Rule-based models work well for well-defined action spaces but struggle with novelty. Classifier-based permission models address this by using a learned model — rather than explicit rules — to decide whether an action is safe, risky, or requires escalation. The classifier generalizes from examples to handle situations that rules could not anticipate."}),e.jsx(t,{title:"Classifier-Based Permission Model",number:"Concept 3.8",children:"In a classifier-based permission model, each proposed action is evaluated by a trained model that assigns it a risk score or category. Actions below a risk threshold proceed automatically. Actions above the threshold are blocked or escalated. The classifier's behavior is not determined by explicit rules but by patterns learned from labeled examples of safe and unsafe actions."}),e.jsx(a,{title:"Email Spam Filters",children:'A spam filter does not have an exhaustive list of spam messages — there are too many and they evolve too quickly. Instead, it learns patterns that correlate with spam across millions of examples and applies those patterns to messages it has never seen. A classifier-based permission model applies the same approach: learn what "risky action" looks like, then apply that understanding to novel situations.'}),e.jsx("p",{children:"Classifier-based models handle ambiguity and novelty much better than rule sets. They can recognize that an action is semantically dangerous even if no explicit rule covers it. However, they introduce new risks: false positives block legitimate actions, false negatives let dangerous actions through, and the decision boundary is opaque — it is not always possible to explain why a specific action was flagged."}),e.jsx(s,{title:"Combining classifiers with rules",type:"info",children:"The most robust permission systems layer both approaches. Hard rules encode absolute constraints that no classifier should be able to override — certain actions are always denied, full stop. The classifier handles the large middle ground of ambiguous cases that rules cannot anticipate. This gives you the predictability of rules where stakes are highest, and the flexibility of classifiers everywhere else."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"cb-1",difficulty:"beginner",question:"What is the key advantage of classifier-based permissions over rule-based permissions when the agent operates in a domain where the range of possible actions is very large or unpredictable?",hint:"Think about what rules require vs. what classifiers require to work.",solution:"Rules require the designers to enumerate all possible dangerous actions in advance — impossible when the action space is vast or evolving. Classifiers generalize from examples to handle actions that were never explicitly defined as safe or unsafe. They can recognize dangerous intent in forms that no specific rule anticipated."},{id:"cb-2",difficulty:"intermediate",question:"A classifier-based safety model has a 2% false negative rate — it fails to flag 2% of truly dangerous actions as risky. At what volume of actions per day does this become a serious operational problem, and what compensating controls would you add?",hint:"Think about absolute numbers at scale.",solution:"At 1,000 actions per day, 2% means 20 dangerous actions slip through — likely unacceptable. At 10,000 actions per day, that's 200. Compensating controls: (1) Post-hoc audit sampling of approved actions to catch misclassifications. (2) Rate limiting to cap potential damage from any single false-negative cluster. (3) Hard rules for the most catastrophic action classes regardless of classifier score."},{id:"cb-3",difficulty:"advanced",question:"An adversary discovers that slightly rephrasing a dangerous instruction causes the classifier to score it as safe. What is this attack called, and what architectural approach makes the system more robust to it?",hint:"This is a well-known class of attack against learned models.",solution:"This is an adversarial example or prompt injection attack against the classifier. Robustness approaches: (1) Semantic ensemble — run multiple independent classifiers and require consensus to approve. (2) Normalization — strip surface variation before classification so rephrasing doesn't change the semantic input. (3) Defense in depth — do not rely solely on the classifier; layer it with rule-based hard stops and post-execution monitoring."}]})]})}const _=Object.freeze(Object.defineProperty({__proto__:null,default:p},Symbol.toStringTag,{value:"Module"}));function g(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Full Trust"}),e.jsx("p",{children:"At the far end of the permission spectrum sits the full-trust model: the agent acts autonomously with no per-action checks, no human approval gates, and no classifier evaluation. Authorization is granted at deployment time and does not constrain individual actions within the session. Full trust maximizes speed and autonomy at the expense of human oversight."}),e.jsx(t,{title:"Full-Trust Permission Model",number:"Concept 3.9",children:"A full-trust model grants an agent unconditional authorization to take any action within its technical capability. Permission is established once — at configuration time — and all subsequent actions are implicitly authorized. There are no checkpoints, escalation paths, or mid-session reviews. The agent's judgment is treated as equivalent to the operator's intent."}),e.jsx("p",{children:`Full trust is not inherently wrong — it is appropriate in tightly constrained environments where the agent's capability is itself the safety boundary. A read-only analytics agent operating on a sandboxed copy of data can safely be given full trust because the worst it can do is return incorrect analysis. The "full trust" is scoped by the environment, not by per-action checks.`}),e.jsx(o,{title:"Full trust requires a safe environment, not just a trusted agent",children:"Full trust is only safe when the environment provides its own containment. Giving an agent full trust over unrestricted production systems is not a permission model — it is an absence of safety design. Before removing permission checks, verify that the environment itself limits the blast radius to an acceptable level."}),e.jsx(s,{title:"Full trust and accountability",type:"info",children:'Even in full-trust deployments, comprehensive logging remains essential. Without a record of what the agent did and why, post-incident investigation is impossible. Full trust removes pre-action approval but should never remove post-action auditability. "Trust but verify after the fact" is a viable model; "trust and never look" is not.'}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"ft-1",difficulty:"beginner",question:"Describe a scenario where full trust is the appropriate permission model. What properties of the environment make it safe to remove per-action checks?",hint:"Think about what constrains the blast radius when there are no permission rules.",solution:"Example: a data analysis agent operating on a read-only snapshot of anonymized data in an isolated compute environment. Safe properties: the environment is read-only (no modifications possible), the data is anonymized (no PII exposure), and the environment is isolated (no connection to production systems). The environment itself is the safety boundary."},{id:"ft-2",difficulty:"intermediate",question:"A team wants to give their deployment agent full trust to speed up the CI/CD pipeline. What three questions should they answer before proceeding, to ensure this is a responsible decision?",hint:"Think about what could go wrong and whether you would notice.",solution:"(1) What is the worst action this agent could take, and is the blast radius of that action acceptable? (2) Is there comprehensive logging so any mistake can be reconstructed and diagnosed? (3) Are there compensating controls outside the agent itself — such as deployment throttles, canary releases, or automatic rollback — that limit damage even if the agent acts incorrectly?"},{id:"ft-3",difficulty:"advanced",question:"Explain why full trust becomes more dangerous as an agent system grows more capable over time, even if the environment and rules don't change.",hint:'Think about what "capability" means for a fixed blast radius.',solution:"A more capable agent can take more complex, non-obvious sequences of individually permitted actions to achieve outcomes the designers never anticipated. A simple agent with full trust over a database might only run straightforward queries. A highly capable agent with the same trust might construct elaborate sequences — exfiltrating data through side channels, or producing outputs that influence downstream systems in unexpected ways. Capability expands the effective action space even when the nominal permissions remain constant."}]})]})}const R=Object.freeze(Object.defineProperty({__proto__:null,default:g},Symbol.toStringTag,{value:"Module"}));function f(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Least Privilege"}),e.jsx("p",{children:"Least privilege is one of the oldest and most important principles in computer security, and it applies directly to agents. It states that any component — human, process, or agent — should have access to exactly what it needs to perform its job, and nothing more. Over-provisioning access is not a convenience feature; it is a safety risk waiting to be realized."}),e.jsx(t,{title:"Least Privilege",number:"Concept 3.10",children:"The principle of least privilege requires that an agent be granted the minimum permissions necessary to complete its intended task. Permissions should be scoped to specific resources, specific actions, and — where possible — specific time windows. Any access not explicitly required for the task is a potential source of unintended harm."}),e.jsx(a,{title:"Hotel Key Cards",children:"A hotel key card opens your room and the gym. It does not open the kitchen, the server room, or other guests' rooms. The hotel doesn't give you a master key and ask you to use good judgment. Each guest gets exactly the access needed for their stay, scoped to the rooms they actually need. Agent permissions should be designed the same way."}),e.jsx("p",{children:"In practice, least privilege requires actively scoping permissions along three dimensions: resource scope (which data or systems can be accessed), action scope (which operations can be performed — read, write, delete), and temporal scope (during what time window access is valid). Most security failures involving agents involve over-permission on at least one of these dimensions."}),e.jsx(n,{title:"Grant Permissions Just In Time",number:"Principle 3.4",children:"Prefer granting permissions at the moment they are needed and revoking them immediately after use, rather than maintaining standing permissions throughout a session. A long-lived session with broad permissions is a much larger attack surface than a series of short-lived, narrowly scoped access grants. Just-in-time permissions minimize the window of exposure."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"lp-1",difficulty:"beginner",question:"An agent is tasked with generating a weekly sales summary report from a database. What is the minimum set of permissions it needs, stated in terms of resource, action, and time scope?",hint:"Think about what the agent needs to read, what it should never touch, and when it runs.",solution:"Resource: read access to the sales tables relevant to the report — no access to HR, financial, or other tables. Action: SELECT only — no INSERT, UPDATE, or DELETE. Time scope: permissions active only during the scheduled report window (e.g., Sunday night), revoked immediately after the report is generated."},{id:"lp-2",difficulty:"intermediate",question:`A developer says "it's easier to give the agent admin access and not worry about scoping." What are three concrete risks this creates, even if the developer trusts the agent completely?`,hint:"Think about what else could go wrong beyond the agent itself misbehaving.",solution:"(1) If the agent's credentials are compromised (e.g., leaked in logs or via prompt injection), attackers gain admin access to the entire system. (2) A bug in the agent's logic could inadvertently use admin access to modify or delete data it was not supposed to touch. (3) Blast radius of any mistake — including honest errors — is maximized: a miscalculation that should affect one table could affect the whole system."},{id:"lp-3",difficulty:"advanced",question:"Explain the tension between least privilege and agent autonomy in multi-step tasks. How can you design a system that honors both?",hint:"Think about what a multi-step agent needs to discover vs. what it needs to know upfront.",solution:"Multi-step agents often don't know exactly which resources they will need until mid-task — requesting least-privilege upfront may be impossible. Tension: granting broad access enables autonomy but violates least privilege; requiring pre-specification of all needed resources enables least privilege but breaks autonomy for exploratory tasks. Resolution: use a dynamic permission request pattern — the agent starts with minimal permissions and requests additional access as each step reveals new needs, with human or automated approval at each escalation point."}]})]})}const z=Object.freeze(Object.defineProperty({__proto__:null,default:f},Symbol.toStringTag,{value:"Module"}));function y(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Fail Closed"}),e.jsx("p",{children:'When something unexpected happens — an ambiguous instruction, a missing permission check, an unanticipated state — the agent must choose a default behavior. The "fail closed" principle says that the safe default is inaction: when in doubt, stop and surface the uncertainty to a human rather than proceeding with a guess. This is the opposite of "fail open," where ambiguity is resolved by proceeding.'}),e.jsx(t,{title:"Fail Closed",number:"Concept 3.11",children:"A fail-closed design causes an agent to stop, report, and wait when it encounters uncertainty, ambiguity, or conditions outside its defined operating envelope. The default action on any undetermined situation is to do nothing and escalate. Fail-closed systems prefer a false positive (unnecessary halt) over a false negative (harmful action taken without authorization)."}),e.jsx("p",{children:"Fail closed is not the same as fail loudly — though both are desirable together. An agent that fails closed should not simply freeze silently; it should communicate clearly what caused the halt, what information is missing, and what the human needs to provide to resume. A well-designed fail-closed system is informative, not just cautious."}),e.jsx(n,{title:"Deny by Default",number:"Principle 3.5",children:"Any action not explicitly permitted should be implicitly denied. Do not build agent systems where ambiguous situations result in a best-guess attempt. The cost of a wrong guess is usually higher than the cost of a halt. Operators can always expand permissions explicitly — they cannot easily undo actions that should have been blocked."}),e.jsx(s,{title:"Fail closed vs. fail safe",type:"info",children:'Fail closed (halt on uncertainty) and fail safe (move to a safe physical state on failure) are related but distinct. In physical systems, a door that locks on power failure "fails safe" — it prevents intrusion. In agent systems, an agent that pauses and asks before acting on ambiguous data "fails closed." Both share the philosophy: choose the outcome with lower expected harm when the system cannot determine the right answer.'}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"fc-1",difficulty:"beginner",question:"An agent receives an instruction that could be interpreted in two ways: one harmless, one destructive. Under fail-closed design, what should it do?",hint:"The ambiguity itself is the trigger for fail-closed behavior.",solution:"The agent should halt and surface the ambiguity explicitly: state both possible interpretations, explain why it cannot resolve the ambiguity autonomously, and ask the human to clarify which interpretation is intended. It should not guess, even if the harmless interpretation seems more likely."},{id:"fc-2",difficulty:"intermediate",question:"A team argues that fail-closed is bad for user experience because it creates too many interruptions. How do you respond, and what design approach reconciles safety with usability?",hint:"Think about how to reduce the frequency of ambiguous situations, not just how to handle them.",solution:"Fail-closed is correct but should be a last resort, not a first resort. Reduce ambiguity upstream: write precise instructions, define clear operating envelopes, and validate inputs before they reach the agent. When fail-closed does trigger, make the escalation fast and the required human input minimal. A well-specified agent rarely needs to fail closed; when it does, the interruption is genuinely warranted."},{id:"fc-3",difficulty:"advanced",question:"Compare the failure modes of fail-open and fail-closed agent designs over time. Which tends to produce more visible failures, and what does this mean for how teams perceive and manage risk?",hint:"Think about which failures are easy to see vs. which accumulate silently.",solution:"Fail-open produces invisible failures: incorrect actions proceed without anyone noticing until downstream consequences appear. Fail-closed produces visible failures: halts are logged and reported immediately. Teams with fail-open systems often underestimate their risk because problems hide until they become large. Fail-closed teams see frequent small interruptions that may feel more burdensome but actually reveal the true rate of ambiguous situations — giving teams actionable data to improve system design."}]})]})}const M=Object.freeze(Object.defineProperty({__proto__:null,default:y},Symbol.toStringTag,{value:"Module"}));function b(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Human in the Loop"}),e.jsx("p",{children:"Human-in-the-loop (HITL) design places a human as an active participant in an agent's decision-making process at defined checkpoints. Unlike pure automation, HITL systems do not aim to remove humans from the loop entirely — they strategically position human judgment where it adds the most value and where automated decisions carry the highest risk."}),e.jsx(t,{title:"Human-in-the-Loop (HITL)",number:"Concept 3.12",children:"A human-in-the-loop design identifies specific decision points in an agent's execution where a human must review, modify, or approve before the agent continues. These checkpoints are pre-defined rather than reactive — they are part of the system design, not emergency interventions. The goal is meaningful oversight, not performative approval."}),e.jsx(a,{title:"Air Traffic Control",children:"Aircraft autopilots handle routine flight — altitude, heading, speed. Air traffic controllers handle complex decisions: sequencing landings, managing conflicts, responding to emergencies. The human is not needed for every control input, but is essential for high-ambiguity, high-stakes decisions that require situational awareness across many concurrent systems. HITL agent design places humans in the air traffic controller role, not the autopilot role."}),e.jsx("p",{children:"Effective HITL design requires matching checkpoint placement to where human judgment is genuinely valuable. Checkpoints placed at low-stakes, routine decisions add friction without adding safety. Checkpoints placed at high-stakes, novel, or irreversible decisions provide real value. The hardest design challenge is identifying which decisions are which, and building the interfaces that give humans enough context to make good decisions quickly."}),e.jsx(s,{title:"HITL requires good interfaces",type:"info",children:"A human-in-the-loop checkpoint is only as good as the information presented to the human. If the approval interface shows opaque technical details without context, the human cannot make an informed decision — they will either approve blindly or experience decision fatigue. HITL interfaces should present the decision in terms the reviewer understands, with clear consequences and a simple action path."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"hitl-1",difficulty:"beginner",question:"What distinguishes a meaningful human-in-the-loop checkpoint from a performative one? Give one characteristic of each.",hint:"Think about whether the human can actually change the outcome.",solution:'Meaningful: the human has sufficient context to make an informed decision and the authority to reject or modify the proposed action. Performative: the human is shown a confirmation dialog with insufficient context to evaluate it, or the system is designed in a way that makes rejection impractical (e.g., "approve or the entire task fails").'},{id:"hitl-2",difficulty:"intermediate",question:"An agent that books travel for employees has a HITL checkpoint for every booking, regardless of cost. Redesign the checkpoint strategy to be more effective without removing human oversight entirely.",hint:"Think about risk-based tiering — what factors determine whether a booking needs review?",solution:"Tier checkpoints by risk: auto-approve bookings under a cost threshold that match pre-specified travel policies (e.g., economy class, preferred vendors, advance booking). Require manager review for bookings above a cost threshold or that deviate from policy. Require executive review for bookings above a higher threshold or for unusual destinations. Most bookings proceed automatically; human oversight concentrates on the decisions that warrant it."},{id:"hitl-3",difficulty:"advanced",question:"As AI agents become more capable, some argue HITL becomes less necessary because the agent's judgment improves. Construct an argument for why HITL remains important even for highly capable agents.",hint:'Think about accountability, alignment, and what "capable" actually measures.',solution:"Capability and alignment are independent. A highly capable agent that is subtly misaligned can cause much larger harm than a less capable one — capability amplifies both good and bad outcomes. Additionally, HITL provides accountability and legitimacy that cannot be replaced by performance metrics. Even if an agent makes correct decisions 99.9% of the time, the 0.1% where it is wrong requires human oversight to catch and correct. Finally, HITL is not just about catching errors — it is about maintaining human understanding of and responsibility for consequential decisions, which is a governance requirement independent of technical capability."}]})]})}const W=Object.freeze(Object.defineProperty({__proto__:null,default:b},Symbol.toStringTag,{value:"Module"}));function v(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Sandboxing"}),e.jsx("p",{children:'Sandboxing is the practice of running an agent inside an isolated environment that limits what real-world effects it can have. The sandbox acts as a physical boundary: regardless of what the agent attempts to do, its actions cannot reach outside the sandbox boundary. This transforms a permission model question ("should the agent be allowed to do X?") into an environment design question ("can the environment be designed so X is impossible?").'}),e.jsx(t,{title:"Sandboxing",number:"Concept 3.13",children:"A sandbox is an isolated execution environment that constrains an agent's ability to affect external systems. The sandbox enforces boundaries at the infrastructure level — network isolation, filesystem restrictions, process limits, and resource caps — making certain classes of harm structurally impossible rather than merely policy-prohibited. No agent instruction or permission grant can break a well-designed sandbox."}),e.jsx(a,{title:"The Terrarium",children:"A terrarium is a glass enclosure for plants and small animals. The inhabitants can live, grow, and interact with each other normally. But they cannot escape the glass. The glass is not a set of rules the inhabitants follow; it is a physical boundary they cannot cross. An agent sandbox works the same way — the boundary is structural, not behavioral."}),e.jsx("p",{children:"Sandboxes serve two safety roles. First, they limit blast radius: even a completely compromised or misbehaving agent cannot affect systems outside the sandbox. Second, they enable experimentation: an agent can be tested against realistic conditions inside a sandbox without risk to production systems. This makes sandboxes valuable both as safety controls and as development tools."}),e.jsx(s,{title:"Sandboxes are not perfect",type:"warning",children:"No sandbox is absolutely impermeable. Side channels, escape vulnerabilities, and supply chain attacks can all compromise sandbox integrity. Sandboxing is one layer in a defense-in-depth strategy — it dramatically reduces risk but should not be the only control. Combine sandboxing with least privilege, monitoring, and human oversight for robust safety."}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"sb-1",difficulty:"beginner",question:'What is the fundamental difference between a rule-based permission that says "the agent should not contact external APIs" and a sandbox that prevents external network connections?',hint:"Think about what enforces each constraint and whether the agent's own behavior matters.",solution:"The rule depends on the agent (and its permission checker) following the constraint — it is a behavioral restriction that could be bypassed if the agent or its permission system is compromised. The sandbox enforces the constraint at the infrastructure level: the network is literally unreachable, regardless of what the agent attempts. The sandbox makes the behavior structurally impossible, not just policy-prohibited."},{id:"sb-2",difficulty:"intermediate",question:"You are designing a sandbox for an agent that needs to: read production logs, generate reports, and email those reports to a fixed list of recipients. Describe the sandbox constraints you would apply.",hint:"Think about the three capabilities the agent needs and what each implies for the sandbox.",solution:"Network: allow outbound connections only to the email relay, and only to the specific recipients in the allowlist — no other outbound access. Filesystem: read-only access to the log directory, write access only to a designated output directory. Compute: resource caps to prevent runaway processes. No access to any production database, API, or internal service beyond the log files."},{id:"sb-3",difficulty:"advanced",question:"An agent inside a well-sandboxed environment produces a report that a human reads and then acts on in the production system. Is the sandbox still providing full protection? What residual risk exists?",hint:"Think about the human as the vector between the sandbox and production.",solution:`The sandbox prevents direct agent actions on production, but it cannot prevent indirect influence through human behavior. If the agent's output is manipulated (via prompt injection or deliberate misinformation in the logs it reads), the human acting on that output becomes the vector for harm. This is sometimes called "indirect prompt injection" — the agent influences production through human intermediaries. Defense: audit and validate agent outputs before acting on them, and treat agent-generated recommendations as proposals requiring independent verification for high-stakes actions.`}]})]})}const B=Object.freeze(Object.defineProperty({__proto__:null,default:v},Symbol.toStringTag,{value:"Module"}));function w(){return e.jsxs("div",{className:"prose-agents",children:[e.jsx("h2",{children:"Secrets and Sensitive Data"}),e.jsx("p",{children:"Agents frequently need to interact with credentials, API keys, personal data, and other sensitive information to do their jobs. How this sensitive data flows through an agent system — and where it comes to rest — is one of the most critical safety and privacy design decisions an agent architect makes."}),e.jsx(t,{title:"Secrets in Agent Systems",number:"Concept 3.14",children:"Secrets are any values that grant access or convey sensitive information: API keys, passwords, tokens, personal identifiers, or confidential content. In agent systems, secrets are dangerous because they can appear in multiple places: the prompt, the conversation history, tool call arguments, tool responses, and logs. Each location is a potential exposure point that must be designed and monitored carefully."}),e.jsx("p",{children:"The most common secret management mistake in agent systems is injecting secrets directly into the agent's context — the prompt or conversation history. Once a secret is in the context, it can be echoed back in agent responses, logged by debugging tools, persisted in conversation history, or leaked through prompt injection. The preferred pattern is for agents to trigger secret-using operations rather than handling secrets directly."}),e.jsx(o,{title:"Secrets in context windows persist",children:`When a secret enters an agent's context window, it is treated like any other text — it may be included in future turns, summarized, logged, or surfaced in error messages. Do not assume that an agent will "know" not to repeat sensitive values. Architectural controls, not behavioral instructions, are the right mechanism for keeping secrets out of agent outputs.`}),e.jsx(n,{title:"Agents Should Trigger, Not Handle",number:"Principle 3.6",children:'Prefer designs where agents trigger operations that use secrets rather than receiving the secrets themselves. An agent that calls a tool named "send_authenticated_request" is safer than one that receives an API key and constructs the request itself. The secret stays in the tool layer, the agent only sees the result. This pattern applies to all sensitive data: the agent reasons about it, but a separate layer handles it.'}),e.jsx(i,{title:"Check Your Understanding",exercises:[{id:"ss-1",difficulty:"beginner",question:"A developer wants to give an agent access to a third-party weather API. They propose including the API key directly in the system prompt. Describe two specific risks this creates.",hint:"Think about where the system prompt content might end up beyond the initial API call.",solution:"(1) The API key may appear in the agent's responses if the user asks about the system configuration or if the agent inadvertently echoes context. (2) If conversation history is logged or persisted, the API key will appear in plaintext logs accessible to anyone with log access — creating a persistent exposure that outlasts the conversation itself."},{id:"ss-2",difficulty:"intermediate",question:"Design an architecture for an agent that needs to make authenticated calls to a financial data API. The agent should never see the API key directly. What components are needed and how do they interact?",hint:'Think about the "trigger, not handle" principle.',solution:"Components: (1) A credential store (e.g., a secrets manager) that holds the API key. (2) A proxy tool service that the agent can call with a request description. (3) The proxy service retrieves the API key from the credential store, makes the authenticated call, and returns only the response data to the agent. The agent calls the proxy tool — it never sees the credential. The key exists only in the credential store and the proxy service's memory during execution."},{id:"ss-3",difficulty:"advanced",question:"An agent is processing customer support tickets that contain PII (names, email addresses, account numbers). The agent needs this information to resolve tickets but it should not be stored in conversation history permanently. Describe a data handling architecture that balances these requirements.",hint:"Think about what needs to persist, what should be ephemeral, and how to link them without exposing the sensitive data.",solution:"Use a reference-token pattern: store PII in a secure, access-controlled customer data store. The agent operates on opaque customer identifiers (tokens) rather than actual PII in its context. When PII is needed for a specific operation, the agent calls a tool that resolves the token to PII internally, performs the operation, and returns a non-PII result. Conversation history stores only tokens. PII access is logged in a dedicated audit system separate from conversation logs, with retention policies aligned to data governance requirements."}]})]})}const E=Object.freeze(Object.defineProperty({__proto__:null,default:w},Symbol.toStringTag,{value:"Module"}));export{j as a,A as b,q as c,P as d,I as e,C as f,S as g,_ as h,R as i,z as j,M as k,W as l,B as m,E as n,T as s};
